DROP TABLE IF EXISTS `cleandata`;

CREATE TABLE `cleandata` (
  `user_id` int DEFAULT NULL,
  `day_type` varchar(7) DEFAULT NULL,
  `work_hours` decimal(10,2) DEFAULT NULL,
  `screen_time_hours` decimal(10,2) DEFAULT NULL,
  `meetings_count` int DEFAULT NULL,
  `breaks_taken` int DEFAULT NULL,
  `after_hours_work` int DEFAULT NULL,
  `sleep_hours` int DEFAULT NULL,
  `task_completion_rate` decimal(10,2) DEFAULT NULL,
  `burnout_score` decimal(10,2) DEFAULT NULL,
  `burnout_risk` varchar(20) DEFAULT NULL
);

